import { createClient } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

const client = createClient({
  publicApiKey: process.env.NEXT_PUBLIC_LIVEBLOCKS_PUBLIC_KEY!,
});

type Presence = {};

type Storage = {
  likes: number;
};

type UserMeta = {};
type RoomEvent = {};
type ThreadMetadata = {};

export const {
  RoomProvider,
  useStorage,
  useMutation,
  useRoom,
} = createRoomContext<Presence, Storage, UserMeta, RoomEvent, ThreadMetadata>(client);

"use client";

import { ReactNode } from "react";
import { RoomProvider } from "../liveblocks.config";
import { ClientSideSuspense } from "@liveblocks/react";

const roomId = `like-button-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;

export function Room({ children }: { children: ReactNode }) {
  return (
    <RoomProvider id={roomId} initialPresence={{}} initialStorage={{ likes: 0 }}>
      <ClientSideSuspense fallback={<div>Loading…</div>}>
        {() => children}
      </ClientSideSuspense>
    </RoomProvider>
  );
}

"use client";

import { useStorage, useMutation } from "../liveblocks.config";

export function LikeButton() {
  const likes = useStorage((root) => root.likes);

  const increment = useMutation(({ storage }) => {
    storage.set("likes", (storage.get("likes") ?? 0) + 1);
  }, []);

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "1rem", marginTop: "2rem" }}>
      <button
        id="like-button"
        onClick={increment}
        style={{
          fontSize: "2rem",
          padding: "0.5rem 2rem",
          cursor: "pointer",
          borderRadius: "8px",
          border: "2px solid #e2e8f0",
          background: "#fff",
        }}
      >
        👍 Like
      </button>
      <span id="like-count" style={{ fontSize: "1.5rem", fontWeight: "bold" }}>
        {likes}
      </span>
    </div>
  );
}

import { Room } from "./Room";
import { LikeButton } from "./LikeButton";

export default function Home() {
  return (
    <main style={{ fontFamily: "sans-serif", textAlign: "center", padding: "2rem" }}>
      <h1>Collaborative Like Button</h1>
      <Room>
        <LikeButton />
      </Room>
    </main>
  );
}

